const staleJobs = Number($json.stale_jobs_recovered || 0);
const staleItems = Number($json.stale_items_recovered || 0);
const cancelled = Number($json.jobs_cancelled || 0);
if (!cancelled || !$json.alert_chat_id) return [];
return [{ json: {
  chat_id: $json.alert_chat_id,
  text: `⚠️ Inbox Agent: ${cancelled} job(s) зупинено після вичерпання повторних спроб. Відновлено stale jobs: ${staleJobs}, stale items: ${staleItems}.`
} }];

if (!$json.chat_id || $json.used_bytes === undefined || $json.threshold_bytes === undefined) return [];
const usedGb = (Number($json.used_bytes) / 1_000_000_000).toFixed(2);
const thresholdGb = (Number($json.threshold_bytes) / 1_000_000_000).toFixed(0);
if (!Number.isFinite(Number($json.used_bytes)) || !Number.isFinite(Number($json.threshold_bytes))) return [];
return [{ json: {
  chat_id: $json.chat_id,
  text: `⚠️ Сховище Inbox Agent досягло ${usedGb} GB із безплатного ліміту. Поріг ${thresholdGb} GB пройдено. Час перевірити B2, очистити дублікати або підготувати платний тариф.`
} }];
